SELECT b.*,
       r.location AS room_location,
       e.position AS booker_position
FROM admin_meeting_booking b
LEFT JOIN admin_meeting_room r ON b.room_id = r.id
LEFT JOIN sys_employee e ON b.booker_id = e.id
WHERE 1=1

    AND b.room_id = #{query.roomId}


    AND b.booker_id = #{query.bookerId}


    AND b.status = #{query.status}


    AND (b.title LIKE CONCAT('%', #{query.keyword}, '%')
         OR b.booker_name LIKE CONCAT('%', #{query.keyword}, '%'))


    AND b.start_time >= #{query.startDate}


    AND b.end_time <= #{query.endDate}

ORDER BY b.start_time DESC

SELECT COUNT(*) FROM admin_meeting_booking
WHERE room_id = #{roomId}
  AND status NOT IN ('cancelled', 'rejected')
  AND (
      (start_time <= #{startTime} AND end_time > #{startTime})
      OR (start_time < #{endTime} AND end_time >= #{endTime})
      OR (start_time >= #{startTime} AND end_time <= #{endTime})
  )

    AND id != #{excludeId}

SELECT * FROM admin_meeting_booking
WHERE room_id = #{roomId}
  AND status NOT IN ('cancelled', 'rejected')
  AND start_time <= #{endDate}
  AND end_time >= #{startDate}
ORDER BY start_time ASC

SELECT * FROM admin_meeting_booking
WHERE status = 'approved'
  AND start_time >= #{startTime}
  AND end_time <= #{endTime}
ORDER BY start_time ASC

SELECT * FROM admin_meeting_booking
WHERE start_time >= #{startDate}
  AND end_time <= #{endDate}
  AND status NOT IN ('cancelled', 'rejected')

SELECT * FROM admin_meeting_booking
WHERE start_time >= #{startDate}
  AND end_time <= #{endDate}
  AND status NOT IN ('cancelled', 'rejected')

SELECT * FROM admin_meeting_booking
WHERE start_time >= #{startDate}
  AND end_time <= #{endDate}
  AND status NOT IN ('cancelled', 'rejected')

SELECT * FROM admin_meeting_booking
WHERE YEAR(start_time) = #{year}
  AND MONTH(start_time) = #{month}
  AND status NOT IN ('cancelled', 'rejected')

SELECT COUNT(*) FROM admin_meeting_booking
WHERE room_id = #{roomId}
  AND status NOT IN ('cancelled', 'rejected')
